const body = $input.item.json.body || {};

const sizeMap = {
  'Solo / freelance': 'Solo',
  '2 à 10 employés': '2-10',
  '11 à 50 employés': '11-50',
  '51 à 200 employés': '51-200',
  '200+ employés': '200+'
};

const sectorMap = {
  'Services / Conseil': 'Services',
  'Industrie / Production': 'Industrie',
  'Commerce / Retail / E-commerce': 'Commerce',
  'Santé / Pharma': 'Santé',
  'Finance / Assurance': 'Finance',
  'Immobilier / Construction': 'Immobilier',
  'Hôtellerie / Restauration': 'Hôtellerie',
  'Autre': 'Autre'
};

const budgetMap = {
  "< 2'000 CHF": '< 2k',
  "2'000 - 5'000 CHF": '2-5k',
  "5'000 - 15'000 CHF": '5-15k',
  "15'000+ CHF": '15k+',
  'À définir': 'À définir'
};

const timingMap = {
  'Ce mois-ci': 'Ce mois',
  'Dans 3 mois': '3 mois',
  "D'ici 6 mois": '6 mois',
  'Je me renseigne': 'Exploration'
};

const name = (body.name || '').trim();
const email = (body.email || '').trim().toLowerCase();
const phone = (body.phone || '').trim();
const company = (body.company || '').trim();
const lastStep = body.lastStep || 1;
const totalSteps = body.totalSteps || 4;

const lines = ['⚠️ *LEAD PARTIEL* — Formulaire abandonné', ''];
if (name) lines.push('👤 ' + name);
if (email) lines.push('📧 ' + email);
if (phone) lines.push('📱 +41 ' + phone);
if (company) lines.push('🏢 ' + company);

const size = body.size ? (sizeMap[body.size] || body.size) : '';
const budget = body.budget ? (budgetMap[body.budget] || body.budget) : '';
const sector = body.sector ? (sectorMap[body.sector] || body.sector) : '';
const timing = body.timing ? (timingMap[body.timing] || body.timing) : '';
const challenge = (body.challenge || '').trim();

if (size) lines.push('👥 ' + size + ' pers.');
if (budget) lines.push('💰 Budget : ' + budget);
if (sector) lines.push('🏭 ' + sector);
if (timing) lines.push('📅 Timing : ' + timing);
if (challenge) lines.push('💬 "' + challenge.substring(0, 80) + (challenge.length > 80 ? '...' : '') + '"');

lines.push('');
lines.push('⏱ Arrêté à l\'étape ' + lastStep + '/' + totalSteps);

const now = new Date(body.submittedAt || Date.now());
const h = String(now.getHours()).padStart(2, '0');
const m = String(now.getMinutes()).padStart(2, '0');
const d = String(now.getDate()).padStart(2, '0');
const mo = String(now.getMonth() + 1).padStart(2, '0');
const y = now.getFullYear();
lines.push('🕐 ' + d + '/' + mo + '/' + y + ' à ' + h + ':' + m);
lines.push('');
lines.push('→ *À contacter rapidement*');

const todayISO = new Date().toISOString().split('T')[0];

return {
  json: {
    telegramMessage: lines.join('\n'),
    nomEntreprise: company || 'Lead partiel — ' + (name || email),
    contactPrincipal: name,
    email: email,
    telephone: phone ? '+41 ' + phone : '',
    taille: size,
    secteur: sector || 'Autre',
    timing: timing,
    budget: budget || 'À définir',
    enjeuPrincipal: challenge,
    datePremierContact: todayISO,
    dateProchaineAction: todayISO,
    prochaineAction: 'URGENT — Lead partiel à contacter (formulaire abandonné étape ' + lastStep + '/' + totalSteps + ')',
    notesText: 'LEAD PARTIEL — Formulaire abandonné à l\'étape ' + lastStep + '/' + totalSteps + '\nSoumis via : ' + (body.pageUrl || 'excilia.ch') + '\nDate : ' + (body.submittedAt || new Date().toISOString())
  }
};
